public void testIssue291_additionalCase1() {
  foldSame("if (f) { f.onclick(); }");
  foldSame("if (f) { f.onload(); }");
  foldSame("if (f) { f.onmouseover(); }");
}

public void testIssue291_additionalCase2() {
  foldSame("if (f) { f.toString(); }");
  foldSame("if (f) { f.valueOf(); }");
}

public void testIssue291_additionalCase3() {
  fold("if (f) { f.regularMethod(); }", "f && f.regularMethod();");
  fold("if (f) { f.myFunction(); }", "f && f.myFunction();");
}

public void testIssue291_additionalCase4() {
  fold("if (true) { regularCall(); }", "if (1) regularCall();");
  fold("if (f) { nonPropertyCall(); }", "f && nonPropertyCall();");
}
